function validateAnchorTag(tag) {
  var href = tag.match(/href="([^"]*)"/);
  var target = tag.match(/target="([^"]*)"/);
  if (href && target) {
    return tag;
  } else if (!href) {
    return tag.replace(/href=""/g, 'href="" target="_self"');
  } else if (target && !['_blank', '_self', '_parent', '_top'].includes(target[1])) {
    return tag.replace(/target="([^"]*)"/g, 'target="_self"');
  } else {
    return tag;
  }
}

