class Solution(object):
    def validateAnchorTag(self, tag: str) -> str:
        import re
        href = re.search(r'href="([^"]*)"', tag)
        target = re.search(r'target="([^"]*)"', tag)
        if href and target:
            return tag
        elif not href:
            return tag.replace('href=""', 'href="" target="_self"')
        elif target and target.group(1) not in ['_blank', '_self', '_parent', '_top']:
            return tag.replace(f'target="{target.group(1)}"', 'target="_self"')
        else:
            return tag
